import React, { useState, useEffect, useCallback, useRef, createContext, useContext } from "react";
import { Link } from "gatsby";
import { useLocation } from "@reach/router";
import SearchBar from "./SearchBar";
import MarketTicker from "./MarketTicker";

const TRANSLATIONS = {
  dashboard: { vi: "Bảng Điều Khiển", en: "Dashboard" },
  reports: { vi: "Báo Cáo", en: "Reports" },
  markets: { vi: "Thị Trường", en: "Markets" },
  plays: { vi: "Cơ Hội", en: "Plays" },
  legal: { vi: "Pháp Lý VN", en: "VN Legal" },
  about: { vi: "Giới Thiệu", en: "About" },
  footer_built: { vi: "Xây dựng bằng ⚡ bởi AI tự động", en: "Built with ⚡ by autonomous agents" },
};

const NAV_ITEMS = [
  { path: "/", key: "dashboard", icon: "📊" },
  { path: "/reports/", key: "reports", icon: "📋" },
  { path: "/markets/", key: "markets", icon: "📈" },
  { path: "/opportunities/", key: "plays", icon: "🎯" },
  { path: "/legal/", key: "legal", icon: "⚖️" },
  { path: "/about/", key: "about", icon: "ℹ️" },
];

export const LangContext = createContext({ lang: "vi" });

export const useLang = () => useContext(LangContext);

export const t = (key, lang) => {
  const entry = TRANSLATIONS[key];
  if (!entry) return key;
  return (entry[lang] || entry.en);
};

// Hydration-safe date — renders nothing on SSR, date on client after mount
const TerminalDate = () => {
  const [date, setDate] = useState(null);
  useEffect(() => { setDate(new Date().toISOString().split("T")[0]); }, []);
  return <span className="terminal-time">{date}</span>;
};

// Pull-to-refresh indicator for mobile (raw DOM events for Safari compat)
const PullToRefresh = ({ children }) => {
  const [ptrState, setPtrState] = useState("idle"); // idle | pulling | refreshing
  const startYRef = useRef(0);

  useEffect(() => {
    if (typeof window === "undefined") return;

    let startY = 0;
    let pulling = false;

    const onTouchStart = (e) => {
      if (window.scrollY <= 1) {
        startY = e.touches[0].clientY;
        pulling = true;
      }
    };

    const onTouchMove = (e) => {
      if (!pulling) return;
      const diff = e.touches[0].clientY - startY;
      if (diff > 70 && window.scrollY <= 1) {
        if (!e.defaultPrevented) e.preventDefault();
        setPtrState("pulling");
      } else {
        setPtrState("idle");
      }
    };

    const onTouchEnd = () => {
      pulling = false;
      if (ptrState === "pulling") {
        setPtrState("refreshing");
        // Use -webkit-transform for Safari overscroll suppression
        document.body.style.overflow = "hidden";
        setTimeout(() => {
          window.location.reload();
        }, 300);
      } else {
        setPtrState("idle");
      }
    };

    document.addEventListener("touchstart", onTouchStart, { passive: true });
    document.addEventListener("touchmove", onTouchMove, { passive: false });
    document.addEventListener("touchend", onTouchEnd, { passive: true });

    return () => {
      document.removeEventListener("touchstart", onTouchStart);
      document.removeEventListener("touchmove", onTouchMove);
      document.removeEventListener("touchend", onTouchEnd);
    };
  }, [ptrState]);

  return (
    <>
      {ptrState === "pulling" && (
        <div className="ptr-indicator">
          <span className="ptr-arrow">↓</span>
          <span>Pull to refresh…</span>
        </div>
      )}
      {ptrState === "refreshing" && (
        <div className="ptr-indicator ptr-loading">
          <span className="ptr-spinner">⟳</span>
          <span>Refreshing…</span>
        </div>
      )}
      {children}
    </>
  );
};

const Layout = ({ children }) => {
  // useLocation works during SSR via Reach Router — no window needed
  const location = useLocation();
  const urlLang = location?.pathname?.startsWith("/en") ? "en" : "vi";
  const [lang, setLang] = useState(urlLang);

  useEffect(() => {
    if (urlLang !== lang) setLang(urlLang);
  }, [urlLang]);

  const toggleLang = () => {
    const newLang = lang === "vi" ? "en" : "vi";
    const p = window.location.pathname;
    let newPath;
    if (lang === "vi" && p.startsWith("/vi")) {
      newPath = p.replace("/vi", "/en");
    } else if (lang === "en" && p.startsWith("/en")) {
      newPath = p.replace("/en", "/vi");
    } else if (newLang === "en") {
      newPath = "/en" + p;
    } else {
      newPath = p;
    }
    window.location.href = newPath;
  };

  const prefix = lang === "en" ? "/en" : "/vi";
  const navPath = (path) => {
    if (path === "/") return prefix + "/";
    return prefix + path;
  };

  return (
    <LangContext.Provider value={{ lang }}>
      <PullToRefresh>
        <div className="terminal-layout">
          <header className="terminal-header">
            <div className="header-left">
              <Link to={prefix + "/"} className="logo-link">
                <img src="/logo.svg" alt="Bobbie Intelligence logo" className="logo" width={32} height={32} />
                <span className="logo-text">Bobbie Intelligence</span>
              </Link>
            </div>
            <nav className="header-nav">
              {NAV_ITEMS.map((item) => (
                <Link key={item.path} to={navPath(item.path)} className="nav-link" activeClassName="nav-link-active">
                  {t(item.key, lang)}
                </Link>
              ))}
            </nav>
            <div className="header-right">
              <SearchBar />
              <div className="lang-switcher-header">
                <button
                  className={`lang-btn ${lang === "vi" ? "lang-btn-active" : ""}`}
                  onClick={lang !== "vi" ? toggleLang : undefined}
                  aria-label="Tiếng Việt"
                >🇻🇳</button>
                <button
                  className={`lang-btn ${lang === "en" ? "lang-btn-active" : ""}`}
                  onClick={lang !== "en" ? toggleLang : undefined}
                  aria-label="English"
                >🇬🇧</button>
              </div>
              <TerminalDate />
            </div>
          </header>

          <MarketTicker />

          <main className="terminal-main">{children}</main>

          <nav className="mobile-nav">
            {NAV_ITEMS.map((item) => (
              <Link key={item.path} to={navPath(item.path)} className="mobile-nav-link" activeClassName="mobile-nav-active">
                <span className="mobile-nav-icon">{item.icon}</span>
                <span className="mobile-nav-label">{t(item.key, lang)}</span>
              </Link>
            ))}
          </nav>

          <footer className="terminal-footer">
            <span>© 2026 Bobbie Intelligence</span>
            <span>{t("footer_built", lang)}</span>
          </footer>
        </div>
      </PullToRefresh>
    </LangContext.Provider>
  );
};

export default Layout;
